pub fn get_coach_state(state: &AppState, student_id: i64) -> Result<CoachStateDto, CommandError> {
    state.with_connection(|conn| {
        let resolution = resolve_coach_state(conn, student_id)?;
        Ok(CoachStateDto::from(resolution))
    })
}

